class Solution(object):
    def freqAlphabets(self, s):
        result = []
        i = len(s) - 1
        while i >= 0:
            if s[i] == '#':
                num = int(s[i-2:i])
                result.append(chr(ord('a') + num - 1))
                i -= 3
            else:
                result.append(chr(ord('a') + int(s[i]) - 1))
                i -= 1
        return ''.join(reversed(result))
